"use client";

import { useEffect } from "react";
import { DisplayMessage } from "@/store/chatStore";
import { EMOTION_EMOJI, MOOD_EMOJI, MOOD_COLOR, formatMoodLabel } from "@/lib/utils";
import { ActivityCard } from "./ActivityCard";
import { SpecialActionCard } from "./SpecialActionCard";
import { MusicCard } from "./MusicCard";
import { JokeCard } from "./JokeCard";
import { ProverbCard } from "./ProverbCard";
import { CelebrationCard } from "./CelebrationCard";
import { TTSControls } from "./TTSControls";
import { useTTS } from "@/hooks/useTTS";
import { Brain } from "lucide-react";

interface MessageBubbleProps {
  message: DisplayMessage;
}

export function MessageBubble({ message }: MessageBubbleProps) {
  const isUser = message.role === "user";
  const response = message.chatResponse;
  const { speak, stop, isSpeaking, voiceGender, setVoiceGender, autoSpeak, setAutoSpeak } = useTTS();

  const mode = response?.response_mode || "support";
  const isPositiveMode = mode === "celebrate" || mode === "reflect";

  // ── Auto-speak when a new assistant message arrives ──────────────────────
  useEffect(() => {
    if (isUser) return;
    if (!message.content) return;
    if (!autoSpeak) return;

    // Small delay so the browser has time to render before speaking
    const timer = setTimeout(() => {
      speak(message.content);
    }, 300);

    return () => {
      clearTimeout(timer);
      // Stop speech when this message unmounts (e.g. chat cleared)
      window.speechSynthesis?.cancel();
    };
    // Only run once when the message first appears — intentionally omit speak/autoSpeak
    // from deps to avoid re-triggering on voice gender change
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [message.id, isUser]);

  return (
    <div className={`flex gap-3 ${isUser ? "flex-row-reverse" : "flex-row"} mb-6`}>

      {/* Avatar */}
      <div className={`flex-shrink-0 w-9 h-9 rounded-full flex items-center justify-center text-sm font-bold
        ${isUser
          ? "bg-gradient-to-br from-purple-500 to-pink-500 text-white"
          : "bg-gradient-to-br from-teal-500 to-cyan-500 text-white"
        }`}
      >
        {isUser ? "You" : <Brain size={16} />}
      </div>

      {/* Content column */}
      <div className={`flex-1 max-w-[85%] ${isUser ? "items-end" : "items-start"} flex flex-col`}>

        {/* Emotion + mood badge */}
        {!isUser && response && (
          <div className="flex items-center gap-2 mb-2 flex-wrap">
            <span className="text-xs text-slate-400">
              {EMOTION_EMOJI[response.detected_emotion] || "💭"}{" "}
              <span className="capitalize">{response.detected_emotion}</span>
            </span>
            <span className="text-slate-600">·</span>
            <span className={`text-xs font-medium ${MOOD_COLOR[response.mood_level] || "text-slate-400"}`}>
              {MOOD_EMOJI[response.mood_level]} {formatMoodLabel(response.mood_level)}
            </span>
            {response.llm_provider && (
              <>
                <span className="text-slate-600">·</span>
                <span className="text-xs text-slate-600">{response.llm_provider}</span>
              </>
            )}
          </div>
        )}

        {/* Message bubble */}
        <div className={`rounded-2xl px-4 py-3 text-sm leading-relaxed
          ${isUser
            ? "bg-gradient-to-br from-purple-600 to-purple-700 text-white rounded-tr-sm"
            : "bg-white/8 border border-white/10 text-slate-100 rounded-tl-sm"
          }`}
        >
          {message.content}
        </div>

        {/* TTS controls — manual replay + voice gender + auto-speak toggle */}
        {!isUser && (
          <TTSControls
            text={message.content}
            isSpeaking={isSpeaking}
            voiceGender={voiceGender}
            autoSpeak={autoSpeak}
            onSpeak={speak}
            onStop={stop}
            onGenderChange={setVoiceGender}
            onAutoSpeakChange={setAutoSpeak}
          />
        )}

        {/* ── POSITIVE MODE: happy / excited / calm ─────────────────────── */}
        {!isUser && isPositiveMode && (
          <>
            {response?.proverb && response?.proverb_author && (
              <div className="w-full">
                <ProverbCard proverb={response.proverb} author={response.proverb_author} />
              </div>
            )}
            {response?.celebration_message && (
              <div className="w-full">
                <CelebrationCard
                  message={response.celebration_message}
                  emotion={response.detected_emotion}
                />
              </div>
            )}
            {response?.music_tracks && response.music_tracks.length > 0 && (
              <div className="w-full">
                <MusicCard tracks={response.music_tracks} />
              </div>
            )}
            {response?.joke && (
              <div className="w-full">
                <JokeCard joke={response.joke} />
              </div>
            )}
          </>
        )}

        {/* ── SUPPORT MODE ─────────────────────────────────────────────── */}
        {!isUser && !isPositiveMode && (
          <>
            {response?.proverb && response?.proverb_author && (
              <div className="w-full">
                <ProverbCard proverb={response.proverb} author={response.proverb_author} />
              </div>
            )}
            {response?.special_action === "breathing_exercise" && response?.special_content && (
              <div className="w-full mt-1">
                <SpecialActionCard actionType="breathing_exercise" content={response.special_content} />
              </div>
            )}
            {response?.joke && (
              <div className="w-full">
                <JokeCard joke={response.joke} />
              </div>
            )}
            {response?.music_tracks && response.music_tracks.length > 0 && (
              <div className="w-full">
                <MusicCard tracks={response.music_tracks} />
              </div>
            )}
            {response?.wellness_tip && (
              <div className="mt-3 w-full bg-teal-500/10 border border-teal-500/20 rounded-xl px-4 py-3">
                <p className="text-teal-300 text-xs leading-relaxed">
                  💡 {response.wellness_tip}
                </p>
              </div>
            )}
            {response?.activities && response.activities.length > 0 && (
              <div className="mt-3 w-full">
                <p className="text-xs text-slate-400 mb-2 font-medium uppercase tracking-wide">
                  🎯 Suggested Activities
                </p>
                <div className="space-y-2">
                  {response.activities.map((activity, i) => (
                    <ActivityCard key={i} activity={activity} index={i} />
                  ))}
                </div>
              </div>
            )}
          </>
        )}

        {/* Timestamp */}
        <span className="text-xs text-slate-600 mt-1 px-1">
          {message.timestamp.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}
        </span>
      </div>
    </div>
  );
}
